), cover_map AS (
  SELECT * FROM payload, jsonb_to_recordset(data->'cover_map') AS x(title_key text, image text, score numeric)
)
UPDATE "Post" p
SET cover_image_url = c.image,
    updated_at = NOW()
FROM cover_map c
