            SELECT jsonb_set(elem, '{data,coverUrl}', to_jsonb(im.image), true)
            FROM item_map im
            WHERE im.title_key = regexp_replace(btrim(p.title_en), '\s+', '_', 'g')
              AND im.item_key = regexp_replace(btrim(COALESCE(elem->'data'->'name'->>'en', elem->'data'->'name'->>'ar', '')), '\s+', '_', 'g')
            LIMIT 1
          ), elem)
        ELSE elem
      END
      ORDER BY ord
    ) AS next_blocks
  FROM "Post" p
  CROSS JOIN LATERAL jsonb_array_elements(COALESCE(p.content_blocks_json::jsonb, '[]'::jsonb)) WITH ORDINALITY AS t(elem, ord)
  GROUP BY p.id
)
UPDATE "Post" p
SET content_blocks_json = r.next_blocks,
    updated_at = NOW()
FROM rebuilt r
WHERE p.id = r.id;

COMMIT;
